import{_ as e,c as a,o as r,aj as t}from"./chunks/framework.CLcCQpUA.js";const i="/ComicGUISpider/assets/CGS-girl.C3XTYkyJ.png",f=JSON.parse('{"title":"简介","description":"","frontmatter":{"title":"简介"},"headers":[],"relativePath":"home/index.md","filePath":"home/index.md"}'),o={name:"home/index.md"},n=t('<p align="center"><picture><img src="'+i+'" width="50%"></picture><a href="https://git.io/typing-svg"><img src="https://readme-typing-svg.demolab.com?font=Fira+Code&amp;weight=700&amp;size=40&amp;duration=3000&amp;pause=10000&amp;color=D39620&amp;center=true&amp;vCenter=true&amp;repeat=false&amp;width=500&amp;lines=ComicGUISpider(CGS)" alt="Typing SVG"></a></p><h2 id="📑-简介" tabindex="-1">📑 简介 <a class="header-anchor" href="#📑-简介" aria-label="Permalink to &quot;📑 简介&quot;">​</a></h2><p><strong><code>CGS</code></strong> 是一个... 能简单使用的漫画下载软件！（忽略200字说明）</p><h2 id="功能说明" tabindex="-1">功能说明 <a class="header-anchor" href="#功能说明" aria-label="Permalink to &quot;功能说明&quot;">​</a></h2><ul><li>简易配置就能使用</li><li>开预览后随便点点就能下载，还能基于预览窗口进网站看</li><li>通过加减号，<code>0 全选</code>，<code>-3 选倒数三个</code> 等输入规则，能方便指定选择</li><li>基于翻页保留，翻页就像已塞进了购物车一样</li><li>虽然任务是顺序流，但内置重启很方便，加上多开更方便</li><li>读剪贴板方式流，字如其名</li><li>去重，加标识符等</li></ul><h2 id="致谢声明" tabindex="-1">致谢声明 <a class="header-anchor" href="#致谢声明" aria-label="Permalink to &quot;致谢声明&quot;">​</a></h2><h3 id="credits" tabindex="-1">Credits <a class="header-anchor" href="#credits" aria-label="Permalink to &quot;Credits&quot;">​</a></h3><p>Thanks to</p><ul><li><a href="https://github.com/skywind3000/PyStand" target="_blank" rel="noreferrer">PyStand</a> / <a href="https://github.com/sveinbjornt/Platypus" target="_blank" rel="noreferrer">Platypus</a> for providing win/macOS packaging.</li><li><a href="https://github.com/sabrogden/Ditto" target="_blank" rel="noreferrer">Ditto</a> / <a href="https://github.com/p0deje/Maccy" target="_blank" rel="noreferrer">Maccy</a> for providing great win/macOS Clipboard Soft.</li><li><a href="https://github.com/zhiyiYo/PyQt-Fluent-Widgets/" target="_blank" rel="noreferrer">PyQt-Fluent-Widgets</a> for providing elegant qfluent ui.</li><li><a href="https://vitepress.dev" target="_blank" rel="noreferrer">VitePress</a> for providing a great documentation framework.</li><li>Every comic production team / translator team / fans.</li></ul><h2 id="贡献" tabindex="-1">贡献 <a class="header-anchor" href="#贡献" aria-label="Permalink to &quot;贡献&quot;">​</a></h2><p>欢迎提供 ISSUE 或者 PR</p><a href="https://github.com/jasoneri/ComicGUISpider/graphs/contributors"><img src="https://contrib.rocks/image?repo=jasoneri/ComicGUISpider"></a><h2 id="传播声明" tabindex="-1">传播声明 <a class="header-anchor" href="#传播声明" aria-label="Permalink to &quot;传播声明&quot;">​</a></h2><ul><li><strong>请勿</strong>将 ComicGUISpider 用于商业用途。</li><li><strong>请勿</strong>将 ComicGUISpider 制作为视频内容，于境内视频网站(版权利益方)传播。</li><li><strong>请勿</strong>将 ComicGUISpider 用于任何违反法律法规的行为。</li></ul><p>ComicGUISpider 仅供学习交流使用。</p><h2 id="licence" tabindex="-1">Licence <a class="header-anchor" href="#licence" aria-label="Permalink to &quot;Licence&quot;">​</a></h2><p><a href="https://github.com/jasoneri/ComicGUISpider/blob/GUI/LICENSE" target="_blank" rel="noreferrer">MIT licence</a></p>',17),l=[n];function s(c,d,h,p,m,g){return r(),a("div",null,l)}const b=e(o,[["render",s]]);export{f as __pageData,b as default};
